class Solution {
    public int[] findOrder(int numCourses, int[][] prerequisites) {
        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < numCourses; i++) graph.add(new ArrayList<>());
        int[] indegree = new int[numCourses];
        for (int[] pre : prerequisites) {
            graph.get(pre[1]).add(pre[0]);
            indegree[pre[0]]++;
        }
        Queue<Integer> queue = new ArrayDeque<>();
        for (int i = 0; i < numCourses; i++) if (indegree[i] == 0) queue.offer(i);
        int[] order = new int[numCourses];
        int idx = 0;
        while (!queue.isEmpty()) {
            int course = queue.poll();
            order[idx++] = course;
            for (int next : graph.get(course)) {
                if (--indegree[next] == 0) queue.offer(next);
            }
        }
        return idx == numCourses ? order : new int[0];
    }
}

class Solution {
    public int[] findOrder(int numCourses, int[][] prerequisites) {
        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < numCourses; i++) graph.add(new ArrayList<>());
        for (int[] pre : prerequisites) graph.get(pre[1]).add(pre[0]);
        int[] visited = new int[numCourses]; // 0 not, 1 visiting, 2 done
        List<Integer> order = new ArrayList<>();
        for (int i = 0; i < numCourses; i++) {
            if (dfs(graph, i, visited, order)) return new int[0];
        }
        Collections.reverse(order);
        return order.stream().mapToInt(i -> i).toArray();
    }
    private boolean dfs(List<List<Integer>> graph, int course, int[] visited, List<Integer> order) {
        if (visited[course] == 1) return true; // cycle
        if (visited[course] == 2) return false;
        visited[course] = 1;
        for (int next : graph.get(course)) {
            if (dfs(graph, next, visited, order)) return true;
        }
        visited[course] = 2;
        order.add(course);
        return false;
    }
}
